text:
if (hasSuffix)
            {
                // suffix
                builder.OpenElement(91, "span");
                builder.AddAttribute(92, "class", $"{PrefixCls}-suffix");

                if (AllowClear)
                {
                    builder.AddContent(93, ClearIcon);
                }

                if (ShowCount)
                {
                    builder.AddContent(110, Counter);
                }

                if (Suffix != null)
                {
                    builder.AddContent(94, Suffix);
                }

                if (FormItem?.FeedbackIcon != null)
                {
                    builder.AddContent(95, FormItem.FeedbackIcon);
                }

                builder.CloseElement();
            }

if (VisibilityToggle)
            {
                Suffix = new RenderFragment((builder) =>
                {
                    if (IconRender is null)
                    {
                        builder.OpenComponent<Icon>(2);
                        builder.AddAttribute(3, "class", $"{PrefixCls}-password-icon");
                        builder.AddAttribute(4, "type", _eyeIcon);
                        builder.AddAttribute(5, "onclick", CallbackFactory.Create<MouseEventArgs>(this, async args =>
                        {
                            ToggleVisibility(args);

                            await Focus(FocusBehavior.FocusAtLast);
                        }));
                        builder.CloseComponent();
                    }
                    else
                    {
                        builder.AddContent(6, IconRender);
                    }
                });
            }

if (firstRender)
            {
                var options = new KeyInterceptorOptions(
                    "mud-button-root",
                    [
                        // prevent scrolling page
                        new(" ", preventDown: "key+none", preventUp: "key+none"),
                        new("Enter", preventDown: "key+none"),
                        new("NumpadEnter", preventDown: "key+none"),
                        new("Backspace", preventDown: "key+none")
                    ]);

                await KeyInterceptorService.SubscribeAsync(_elementId, options, keys => keys
                    .When(CanHandleKeys, builder => builder
                        .OnKeyDown("Delete", () => SetBoolValueAsync(false, true))
                        .OnKeyDownAny(["Enter", "NumpadEnter"], () => SetBoolValueAsync(true, true))
                        .OnKeyDown("Backspace", HandleBackspaceAsync)
                        .OnKeyDown(" ", HandleSpaceAsync)));
            }

foreach (var rule in _rules)
            {
                if (rule.Required == true && !IsRequired)
                {
                    continue;
                }

                var validationContext = new FormValidationContext()
                {
                    Rule = rule,
                    Value = propertyValue,
                    FieldName = _fieldIdentifier.FieldName,
                    DisplayName = DisplayName ?? _propertyReflector.PropertyName,
                    FieldType = _valueUnderlyingType,
                    ValidateMessages = validateMessages,
                    Model = Form.Model
                };

                var result = FormValidateHelper.GetValidationResult(validationContext);

                if (result != null)
                {
                    results.Add(result);
                }
            }

try
            {
                await JS.InvokeAsync<double[]>(JSInteropConstants.SetPopShowFlag, true);

                // Always select the first option
                ActiveOptionValue = ShowOptions.FirstOrDefault()?.Value;

                // Recalculate position each time shown
                var pos = await JS.InvokeAsync<double[]>(JSInteropConstants.GetCursorXY, _overlayTrigger.RefBack.Current);
                var x = (int)Math.Round(pos[0]);
                var y = (int)Math.Round(pos[1]);
                await _overlayTrigger.Show(x, y);

                await InvokeStateHasChangedAsync();
            }
            catch (JSException)
            {
                // Ignore JS exceptions during test scenarios
            }

if (Visible)
            {
                if (e.Key == "Tab")
                {
                    var activeElement = await JsInvokeAsync<string>(JSInteropConstants.GetActiveElement, _sentinelEnd);
                    if (e.ShiftKey)
                    {
                        if (activeElement == _sentinelStart)
                        {
                            await JsInvokeAsync(JSInteropConstants.Focus, "#" + _sentinelEnd);
                        }
                    }
                    else if (activeElement == _sentinelEnd)
                    {
                        await JsInvokeAsync(JSInteropConstants.Focus, "#" + _sentinelStart);
                    }
                }
            }

if (builder.Resource.RequiresImageBuild())
            {
                var buildStep = new PipelineStep
                {
                    Name = $"build-{builder.Resource.Name}",
                    Action = async ctx =>
                    {
                        var containerImageBuilder = ctx.Services.GetRequiredService<IResourceContainerImageManager>();
                        await containerImageBuilder.BuildImageAsync(
                            builder.Resource,
                            ctx.CancellationToken).ConfigureAwait(false);
                    },
                    Tags = [WellKnownPipelineTags.BuildCompute],
                    RequiredBySteps = [WellKnownPipelineSteps.Build],
                    DependsOnSteps = [WellKnownPipelineSteps.BuildPrereq, WellKnownPipelineSteps.CheckContainerRuntime],
                    Resource = builder.Resource
                };
                steps.Add(buildStep);
            }

if (options.AuthMode is ResourceServiceAuthMode.ApiKey)
        {
            if (!Request.Headers.TryGetValue(ApiKeyHeaderName, out var headerValues))
            {
                return Task.FromResult(AuthenticateResult.Fail($"'{ApiKeyHeaderName}' header not found"));
            }

            if (headerValues.Count != 1)
            {
                return Task.FromResult(AuthenticateResult.Fail($"Expecting only a single '{ApiKeyHeaderName}' header."));
            }

            if (!CompareHelpers.CompareKey(expectedKeyBytes: options.GetApiKeyBytes(), requestKey: headerValues.ToString()))
            {
                return Task.FromResult(AuthenticateResult.Fail($"Invalid '{ApiKeyHeaderName}' header value."));
            }
        }

if (context.Resource.TryGetAnnotationsOfType<ContainerFileSystemCallbackAnnotation>(out var createFileAnnotations))
        {
            foreach (var a in createFileAnnotations)
            {
                var entries = await a.Callback(
                    new()
                    {
                        Model = context.Resource,
                        Services = _executionContext.Services,
                        HttpsCertificateContext = context.HttpsCertificateContext,
                    },
                    cancellationToken).ConfigureAwait(false);

                if (entries?.Any() != true)
                {
                    continue;
                }

                createFiles.Add(new ContainerCreateFileSystem
                {
                    Destination = a.DestinationPath,
                    DefaultOwner = a.DefaultOwner,
                    DefaultGroup = a.DefaultGroup,
                    Umask = (int?)a.Umask,
                    Entries = entries.Select(e => e.ToContainerFileSystemEntry()).ToList(),
                });
            }
        }

for (var seriesIndex = 0; seriesIndex < seriesData.Count; seriesIndex++)
        {
            var series = seriesData[seriesIndex];

            if (series.Data == null || series.Data.Count == 0 || !series.Visible || HiddenIndices.Contains(seriesIndex))
            {
                continue;
            }

            var (pathString, points) = GeneratePolygonPath(series, seriesIndex, numAxes, angleStep, currentAngle, radius, axisMaxValue);

            var path = new SvgPolygon
            {
                Index = seriesIndex,
                Data = pathString,
                Points = points,
                LabelXValue = ChartOptions.ShowAsPercentage
                    ? ToS(Math.Round(normalizedData[seriesIndex] * 100, 1)) + "%"
                    : series.Data.Values.SumGeneric().ToString(null, CultureInfo.InvariantCulture),
                LabelYValue = series.Name
            };

            _paths.Add(path);
        }

if (DataGrid.ColumnResizeMode == ResizeMode.Column && Column is not null)
            {
                // Find next resizable column
                var columns = DataGrid.RenderedColumns;
                var currentIndex = columns.IndexOf(Column);
                var nextIndex = currentIndex + (RightToLeft ? -1 : 1);

                _resizeNextColumn = columns.Skip(nextIndex)
                    .FirstOrDefault(c => (c.Resizable ?? true) && !c.HiddenState.Value);

                if (_resizeNextColumn?.HeaderCell is not null)
                {
                    _resizeNextStartWidth = await _resizeNextColumn.HeaderCell.GetCurrentCellWidth();
                }
                else
                {
                    return; // Cannot resize if no next column available
                }
            }

if (DataGrid.FilterMode == DataGridFilterMode.Simple && filterDefinition != null)
            {
                var filterDefinitionToFocus = DataGrid.FilterDefinitions
                    .FirstOrDefault(x => x.Title == filterDefinition.Title);

                if (filterDefinitionToFocus is null)
                {
                    filterDefinitionToFocus = filterDefinition.Clone();
                    DataGrid.FilterDefinitions.Add(filterDefinitionToFocus);
                }

                DataGrid.SetFiltersMenuPosition(args.PageY, args.PageX);
                DataGrid.OpenFilters(filterDefinitionToFocus.Id);
            }
            else if (DataGrid.FilterMode == DataGridFilterMode.ColumnFilterMenu)
            {
                _filtersMenuPosition = (args.PageY, args.PageX);
                _filtersMenuVisible = true;
                DataGrid.DropContainerHasChanged();
            }

if (DataGrid.FilterMode == DataGridFilterMode.Simple)
            {
                var filterDefinitionToFocus = DataGrid.FilterDefinitions
                    .FirstOrDefault(x =>
                        ReferenceEquals(x.Column, Column) ||
                        (Column?.PropertyName is not null && x.Column?.PropertyName == Column.PropertyName));

                DataGrid.SetFiltersMenuPosition(args.PageY, args.PageX);
                DataGrid.OpenFilters(filterDefinitionToFocus?.Id);
            }
            else if (DataGrid.FilterMode == DataGridFilterMode.ColumnFilterMenu)
            {
                _filtersMenuPosition = (args.PageY, args.PageX);
                _filtersMenuVisible = true;
                DataGrid.DropContainerHasChanged();
            }

if (value)
            {
                if (!MultiSelection)
                {
                    Selection.Clear();
                }

                Selection.Add(item);
                await _selectedItemState.SetValueAsync(item);
            }
            else
            {
                Selection.Remove(item);
                if (Comparer != null)
                {
                    if (Comparer.Equals(item, _selectedItemState.Value))
                    {
                        await _selectedItemState.SetValueAsync(default);
                    }
                }
                else
                {
                    if (item.Equals(_selectedItemState.Value))
                    {
                        await _selectedItemState.SetValueAsync(default);
                    }
                }
            }

switch (CurrentView)
            {
                case OpenTo.Date:
                    if (HighlightedDate != null)
                        await OnDayClickedAsync(HighlightedDate.Value);
                    break;
                case OpenTo.Year:
                    if (HighlightedDate != null)
                        await OnYearClickedAsync(GetCulture().Calendar.GetYear(HighlightedDate.Value));
                    break;
                case OpenTo.Month:
                    if (HighlightedDate != null)
                        await OnMonthSelectedAsync(HighlightedDate.Value.StartOfMonth(GetCulture()));
                    break;
                default:
                    await SubmitAsync();
                    _inputReference?.SetTextAsync(Text);
                    await CloseAsync();
                    break;
            }

if (e.Success)
            {
                if (e.OriginatedDropzoneIdentifier == Identifier && e.DestinationDropzoneIdentifier != e.OriginatedDropzoneIdentifier)
                {
                    if (e.Item is not null)
                    {
                        _indices.Remove(e.Item);
                    }
                }

                if (e.OriginatedDropzoneIdentifier == Identifier || e.DestinationDropzoneIdentifier == Identifier)
                {
                    var index = 0;

                    foreach (var item in _indices.OrderBy(x => x.Value).ToArray())
                    {
                        _indices[item.Key] = index++;
                    }
                }
            }

if (Sizing != InputSizing.Fixed)
            {
                if (firstRender || _shouldInitSizing)
                {
                    ResetAutoSizingFlags();
                    await JsRuntime.InvokeVoidAsyncWithErrorHandling("mudInputSizing.init", ElementReference, MaxLines);
                    SyncAutoSizingTextSnapshot();
                }
                else if (_shouldUpdateSizingParams)
                {
                    _shouldUpdateSizingParams = false;
                    _shouldAdjustSizingAfterRender = false;
                    await JsRuntime.InvokeVoidAsyncWithErrorHandling("mudInputSizing.updateParams", ElementReference, MaxLines);
                    SyncAutoSizingTextSnapshot();
                }
                else if (_shouldAdjustSizingAfterRender || _oldText != _internalText)
                {
                    _shouldAdjustSizingAfterRender = false;
                    await JsRuntime.InvokeVoidAsyncWithErrorHandling("mudInputSizing.adjustHeight", ElementReference);
                    SyncAutoSizingTextSnapshot();
                }
            }

if (_focusedIndex >= 0 && _focusedIndex < _menuItems.Count)
            {
                var currentItem = _menuItems[_focusedIndex];

                switch (currentItem)
                {
                    case MudMenuItem menuItem:
                        var submenu = FindSubmenuForItem(menuItem);
                        if (submenu != null)
                        {
                            await submenu.OpenSubMenuAsync(EventArgs.Empty);
                        }
                        else
                        {
                            await menuItem.OnClick.InvokeAsync();
                        }
                        break;

                    case MudMenu menu:
                        await menu.OpenSubMenuAsync(EventArgs.Empty);
                        break;
                }
            }

if (_afterFirstRender)
            {
                if (AutoSize && _valueHasChanged)
                {
                    _valueHasChanged = false;
                    if (_isInputing)
                    {
                        _isInputing = false;
                    }
                    else if (_afterFirstRender)
                    {
                        await JsInvokeAsync(JSInteropConstants.InputComponentHelper.ResizeTextArea, Ref, InnerMinRows, MaxRows);
                    }
                }
                if (_styleHasChanged)
                {
                    _styleHasChanged = false;
                    if (AutoSize && !string.IsNullOrWhiteSpace(Style) && _afterFirstRender)
                    {
                        await JsInvokeAsync(JSInteropConstants.StyleHelper.SetStyle, Ref, Style);
                    }
                }
            }

while (find)
        {
            var (key, subscription) = domEventSubscriptionStore.FindDomEventSubscription(_id);
            if (key != null && subscription != null)
            {
                var tempList = domEventSubscriptionStore[key];
                tempList.Remove(subscription);

                if (tempList.Count == 0 && _sharedDotNetObjectStore.TryGetValue(key, out var dotNetObject))
                {
                    jsRuntime.InvokeVoidAsync(JSInteropConstants.RemoveDomEventListener, key.Selector, key.EventName, dotNetObject);

                    domEventSubscriptionStore.Remove(key, out var _);
                }
            }
            else
            {
                find = false;
            }
        }

if (Picker == DatePickerType.Week)
                {
                    var calendar = CultureInfo.Calendar;
                    var calendarWeekRule = CultureInfo.DateTimeFormat.CalendarWeekRule;

                    var date1Week = calendar.GetWeekOfYear(date1, calendarWeekRule, Locale.FirstDayOfWeek);
                    var date2Week = calendar.GetWeekOfYear(date2, calendarWeekRule, Locale.FirstDayOfWeek);
                    return index == 0 ? date1Week < date2Week && date1.Year <= date2.Year
                                        : date1.Year >= date2.Year && date1Week > date2Week;
                }
                else
                {
                    var formattedDate1 = DateHelper.FormatDateByPicker(date1, Picker);
                    var formattedDate2 = DateHelper.FormatDateByPicker(date2, Picker);
                    return index == 0 ? formattedDate1 < formattedDate2 : formattedDate1 > formattedDate2;
                }

if (_pendingDraft != null)
            {
                var recoveredData = _pendingDraft.Data;

                if (OnUpdate.HasDelegate)
                {
                    await OnUpdate.InvokeAsync(recoveredData);
                }
                else if (DataChanged.HasDelegate)
                {
                    await DataChanged.InvokeAsync(recoveredData);
                }

                if (OnRecovered.HasDelegate)
                {
                    await OnRecovered.InvokeAsync(recoveredData);
                }

                _currentData = recoveredData;
                _currentDataJson = JsonSerializer.Serialize(recoveredData);
                _pendingDraft = null;

                StateHasChanged();
            }

if (parentCultureName != string.Empty)
            {
                if (TryGetSpecifiedLocale(parentCultureName, out locale))
                {
                    AddClonedLocale(cultureName, ref locale);
                    return locale;
                }
                if (cultureName.Count(c => c == '-') == 2)
                {
                    var lang = cultureName[..cultureName.IndexOf('-')];
                    var region = cultureName[cultureName.LastIndexOf('-')..];
                    if (TryGetSpecifiedLocale(lang + region, out locale))
                    {
                        AddClonedLocale(cultureName, ref locale);
                        return locale;
                    }
                }
                parentCultureName = GetParentCultureName(parentCultureName);
                if (parentCultureName != string.Empty && TryGetSpecifiedLocale(parentCultureName, out locale))
                {
                    AddClonedLocale(cultureName, ref locale);
                    return locale;
                }
            }

if (LoadOptions is null)
            {
                var optionsToShow = OriginalOptions.Where(x => x.Value.Contains(searchValue, StringComparison.OrdinalIgnoreCase)).ToList();
                SetOptionsToShow(optionsToShow);
            }
            else
            {
                _cancellationTokenSource?.Cancel();
                _cancellationTokenSource = new CancellationTokenSource();

                try
                {
                    var options = await LoadOptions.Invoke(searchValue, _cancellationTokenSource.Token).ConfigureAwait(false);
                    SetOptionsToShow(options);
                }
                catch (OperationCanceledException)
                {
                    // Operation was cancelled, ignore
                }
            }

if (config.AnimationClass == MessageAnimationType.Enter)
            {
                config.AnimationClass = MessageAnimationType.Leave;
                InvokeAsync(StateHasChanged);
                config.InvokeOnClose();

                if (config.WaitForAnimation)
                {
                    return Task.Delay(500)
                        .ContinueWith((result) =>
                        {
                            _configDict.TryRemove(config.Key, out _);
                            InvokeAsync(StateHasChanged);
                        }, TaskScheduler.Current);
                }
                else
                {
                    _ = Task.Run(async () =>
                    {
                        await Task.Delay(500);
                        _configDict.TryRemove(config.Key, out _);
                        await InvokeAsync(StateHasChanged);
                    });
                    return Task.CompletedTask;
                }
            }

if (configJson["runtimeOptions"]?.AsObject() is { } runtimeOptions &&
            runtimeOptions["frameworks"]?.AsArray() is { } frameworks)
        {
            foreach (var framework in frameworks)
            {
                if (framework?.AsObject() is { } frameworkObj &&
                    frameworkObj["name"]?.GetValue<string>() is { } name &&
                    frameworkObj["version"]?.GetValue<string>() is { } version)
                {
                    switch (name)
                    {
                        case "Microsoft.NETCore.App":
                            netCoreVersion = version;
                            break;
                        case "Microsoft.AspNetCore.App":
                            aspNetCoreVersion = version;
                            break;
                    }
                }
            }
        }

for (var i = 0; i < Math.Min(series.Data.Values.Count, numAxes); i++)
        {
            var value = series.Data[i].Y;
            var scale = radius * (axisMaxValue == 0 ? 0 : double.CreateSaturating(value) / axisMaxValue);
            scale = Math.Max(0, scale);

            var angle = currentAngle + (i * angleStep);
            var x = Math.Cos(angle) * scale;
            var y = Math.Sin(angle) * scale;

            path.Append($"{ToS(x)} {ToS(y)} L ");
            points.Add(new SvgPathPoint
            {
                Index = seriesIndex,
                PointIndex = i,
                LabelX = x,
                LabelY = y,
                LabelXValue = value.ToString(null, CultureInfo.InvariantCulture),
                LabelYValue = series.Name
            });
        }

if (ChartOptions?.NodeOverrides is { Count: > 0 } overrides)
            {
                _nodeLookup = overrides.ToDictionary(d => d.Name);

                Nodes = [.. Nodes.Select(n =>
                {
                    if (_nodeLookup.TryGetValue(n.Name, out var definition))
                    {
                        return n with { Column = definition.Column, Color = definition.Color ?? n.Color };
                    }
                    return n;
                })];

                var existing = Nodes.Select(n => n.Name).ToHashSet();

                Nodes.UnionWith(overrides
                     .Where(o => !existing.Contains(o.Name))
                     .Select(o => new SankeyNode(o.Name, o.Column, o.Color))
                );
            }

for (var i = 0; i < ChartLabels.Length; i++)
            {
                if (_hiddenNodes.Contains(ChartLabels[i]))
                    continue;

                var label = ChartLabels[i];
                var data = new List<(SankeyLink, T)>();

                foreach (var series in visibleSeries)
                {
                    var values = series.Data?.Values ?? [];

                    if (i < values.Count)
                    {
                        var link = new SankeyLink(label, series.Name);
                        data.Add((link, values[i]));
                    }
                }

                result.Add(new ChartSeries<T>
                {
                    Name = label,
                    Data = data.ToArray(),
                    Visible = true
                });
            }

for (var j = 0; j < numVerticalLines; j++)
            {
                var x = barPositions.Length == 0 ? 0 : barPositions[j];

                var line = new SvgPath()
                {
                    Index = j,
                    Data = $"M {ToS(x)} {ToS(_boundHeight - VerticalStartSpace)} L {ToS(x)} {ToS(VerticalEndSpace)}"
                };
                VerticalLines.Add(line);

                var label = j < ChartLabels.Length ? ChartLabels[j] : "";
                var text = new SvgText()
                {
                    X = x,
                    Y = _boundHeight - XAxisLabelOffset,
                    Value = label,
                };
                VerticalValues.Add(text);
            }

for (var i = 0; i < Series.Count; i++)
        {
            var series = Series[i];
            var points = series.Data.Points;
            var data = new TimeValue<T>[points.Count];

            for (var j = 0; j < points.Count; j++)
            {
                var point = points[j];
                var date = point.X switch
                {
                    DateTime dt => dt,
                    null => DateTime.MinValue,
                    string s when DateTime.TryParse(s, out var parsed) => parsed,
                    _ => throw new InvalidOperationException($"Unable to parse '{point.X}' as DateTime for time series chart")
                };

                data[j] = new TimeValue<T>(date, point.Y);
            }

            _cachedDataPoints[i] = data;
        }

if (!checkbox.IsFromOptions)
            {
                if (checkbox.ItemValue != null)
                {
                    checkbox.SetValue(_selectedValues.Any(x => checkbox.ItemValue.Equals(x)));
                }
                else
                {
                    checkbox.SetValue(_selectedValues.Any(x => x.ToString() == checkbox.Label));
                    checkbox.SetItemValue(checkbox.Label);
                }

                if (_indexConstructedOptionsOffset == -1)
                    _indexConstructedOptionsOffset = _checkboxItems.Count - 1;
            }
            else if (checkbox.IsFromOptions && _indexSetOptionsOffset == -1)
                _indexSetOptionsOffset = _checkboxItems.Count - 1;

if (_shouldGenerateFieldNames)
                {
                    if (_formattedValueExpression is null)
                    {
                        if (ValueExpression is not null)
                        {
                            _formattedValueExpression = FieldPrefix != null ? FieldPrefix.GetFieldName(ValueExpression) : ExpressionFormatter.FormatLambda(ValueExpression);
                        }
                        else if (!string.IsNullOrWhiteSpace(Form?.Name) && !string.IsNullOrWhiteSpace(FormItem?.Name))
                        {
                            _formattedValueExpression = $"{Form?.Name}.{FormItem.Name}";
                        }
                    }

                    return _formattedValueExpression ?? string.Empty;
                }

if (index == 0)
            {
                // change start picker value
                if (!_inputStart.IsOnFocused && _pickerStatus[index].IsValueSelected && !UseDefaultPickerValue[index])
                {
                    GetIfNotNull(Value, index, notNullValue =>
                    {
                        ChangePickerValue(notNullValue, index);
                    });
                }

                ChangeFocusTarget(true, false);
            }
            else
            {
                // change end picker value
                if (!_inputEnd.IsOnFocused && _pickerStatus[index].IsValueSelected && !UseDefaultPickerValue[index])
                {
                    GetIfNotNull(Value, index, notNullValue =>
                    {
                        ChangePickerValue(notNullValue, index);
                    });
                }

                ChangeFocusTarget(false, true);
            }

if (_duringPressEnterArgs != null)
            {
                if (_duringPressEnterArgs.ShouldPreventLineBreak)
                {
                    if (_inputString?.EndsWith('\n') == true)
                    {
                        // Only remove the last line break
                        if (_inputString.EndsWith("\r\n"))
                        {
                            _inputString = _inputString[..^2];
                        }
                        else
                        {
                            _inputString = _inputString[..^1];
                        }
                        ForceUpdateValueString(_inputString);
                    }
                }

                _duringPressEnterArgs = null;
            }

if (!Multiple)
            {
                foreach (MenuItem menuitem in _menuItems.Where(x => x != item))
                {
                    if (item.RouterLink != null && menuitem.RouterLink != null && menuitem.RouterLink.Equals(item.RouterLink) && !menuitem.IsSelected)
                    {
                        menuitem.Select();
                        selectedKeys.Add(menuitem.Key);
                    }
                    else if (menuitem.IsSelected || menuitem.FirstRun)
                    {
                        if (!menuitem.FirstRun)
                            skipParentSelection = item.ParentMenu?.Key == menuitem.ParentMenu?.Key;
                        menuitem.Deselect(skipParentSelection);
                    }
                }
            }

if (configJson["runtimeOptions"]?.AsObject() is { } runtimeOptions &&
            runtimeOptions["frameworks"]?.AsArray() is { } frameworks)
        {
            foreach (var framework in frameworks)
            {
                if (framework?.AsObject() is { } frameworkObj &&
                    frameworkObj["name"]?.GetValue<string>() is { } name)
                {
                    switch (name)
                    {
                        case "Microsoft.NETCore.App":
                            frameworkObj["version"] = netCoreVersion;
                            break;
                        case "Microsoft.AspNetCore.App":
                            frameworkObj["version"] = aspNetCoreVersion;
                            break;
                    }
                }
            }
        }

if (string.IsNullOrEmpty(_internalFormat))
                {
                    if (!string.IsNullOrEmpty(Format))
                        _internalFormat = Format;
                    else
                        _internalFormat = _pickerStatus[0].InitPicker.Value switch
                        {
                            DatePickerType.Date => GetTimeFormat(),
                            DatePickerType.Month => Locale.Lang.YearMonthFormat,
                            DatePickerType.Year => Locale.Lang.YearFormat,
                            DatePickerType.Time when Use12Hours => Locale.Lang.TimeFormat12Hour,
                            DatePickerType.Time => Locale.Lang.TimeFormat,
                            DatePickerType.Week => $"{Locale.Lang.YearFormat}-0{Locale.Lang.Week}",
                            DatePickerType.Quarter => $"{Locale.Lang.YearFormat}-Q0",
                            _ => Locale.Lang.DateFormat,
                        };
                }

if (Effect == CarouselEffect.ScrollX && IsHorizontal)
                {
                    return $"width: {TotalWidth}px; opacity: 1; transform: translate3d(-{SlickWidth * (IndexOfSlick(ActiveSlick) + 1)}px, 0px, 0px);transition: -webkit-transform 500ms ease 0s;";
                }
                else if (Effect == CarouselEffect.ScrollX && !IsHorizontal)
                {
                    return $"height: {TotalHeight}px; opacity: 1; transform: translate3d(0px, -{SlickHeight * (IndexOfSlick(ActiveSlick) + 1)}px, 0px);transition: -webkit-transform 500ms ease 0s;";
                }
                else if (Effect == CarouselEffect.Fade && IsHorizontal)
                {
                    return $"width: {TotalWidth}px; opacity: 1;";
                }
                else if (Effect == CarouselEffect.Fade && !IsHorizontal)
                {
                    return $"height: {TotalHeight}px; opacity: 1;";
                }

if (DefaultPickerValue?.Equals(default(TValue)) == true)
            {
                if ((IsNullable && Value != null) || (!IsNullable && !Value.Equals(default(TValue))))
                {
                    DefaultPickerValue = Value;
                }
                else if ((IsNullable && DefaultValue != null) || (!IsNullable && !DefaultValue.Equals(default(TValue))))
                {
                    DefaultPickerValue = DefaultValue;
                    if (!DefaultValue.Equals(Value))
                    {
                        CurrentValue = DefaultValue;
                    }
                }
                else if (!IsNullable && Value.Equals(default(TValue)))
                {
                    DefaultPickerValue = Value;
                }
                else
                {
                    UseDefaultPickerValue[0] = false;
                }
            }

if (ShowTime.Value != null)
            {
                if (ShowTime.IsT0 && ShowTime.AsT0)
                {
                    return dateTime.AddMilliseconds(-dateTime.Millisecond);
                }

                if (ShowTime.IsT1 && !string.IsNullOrEmpty(ShowTime.AsT1))
                {
                    var date = dateTime.Date;
                    var splits = ShowTime.AsT1.Split(':');
                    foreach (var item in splits)
                    {
                        switch (item.ToLowerInvariant())
                        {
                            case "hh": date = date.AddHours(dateTime.Hour); break;
                            case "mm": date = date.AddMinutes(dateTime.Minute); break;
                            case "ss": date = date.AddSeconds(dateTime.Second); break;
                        }
                    }

                    return date;
                }
